  ".ns-desktop-update-prompt {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: var(--ns-space-4);\n  border: 1px solid var(--ns-border);\n  border-inline-start: var(--ns-space-1) solid var(--ns-primary);\n  border-radius: var(--ns-radius-md);\n  padding: var(--ns-space-3) var(--ns-space-4);\n  background: color-mix(in srgb, var(--ns-primary) 7%, var(--ns-surface));\n  color: var(--ns-fg);\n}\n\n.ns-desktop-update-prompt[data-state='manual'] {\n  border-inline-start-color: var(--ns-warning);\n  background: color-mix(in srgb, var(--ns-warning) 8%, var(--ns-surface));\n}\n\n.ns-desktop-update-prompt__copy {\n  display: grid;\n  min-inline-size: 0;\n  gap: var(--ns-space-1);\n}\n\n.ns-desktop-update-prompt__title,\n.ns-desktop-update-prompt__description,\n.ns-desktop-update-prompt__action {\n  font-family: var(--ns-font-sans);\n}\n\n.ns-desktop-update-prompt__title {\n  font-size: var(--ns-text-sm);\n  line-height: var(--ns-leading-tight);\n}\n\n.ns-desktop-update-prompt__description {\n  color: var(--ns-muted-fg);\n  font-size: var(--ns-text-xs);\n  line-height: var(--ns-leading-normal);\n}\n\n.ns-desktop-update-prompt__action {\n  flex: none;\n  border: 1px solid var(--ns-primary);\n  border-radius: var(--ns-radius-sm);\n  padding: var(--ns-space-2) var(--ns-space-3);\n  background: var(--ns-primary);\n  color: var(--ns-primary-fg);\n  cursor: pointer;\n  font-size: var(--ns-text-xs);\n  font-weight: 600;\n  line-height: 1;\n  text-decoration: none;\n  transition:\n    background var(--ns-ease-fast),\n    box-shadow var(--ns-ease-fast),\n    transform var(--ns-ease-fast);\n}\n\n.ns-desktop-update-prompt__action:hover {\n  background: var(--ns-primary-hover);\n  box-shadow: 2px 2px 0 color-mix(in srgb, var(--ns-primary) 55%, var(--ns-gray-12));\n  transform: translate(1px, 1px);\n}\n\n.ns-desktop-update-prompt__action:focus-visible {\n  outline: 2px solid var(--ns-ring);\n  outline-offset: 2px;\n}\n\n@media (max-width: 36rem) {\n  .ns-desktop-update-prompt {\n    align-items: stretch;\n    flex-direction: column;\n  }\n\n  .ns-desktop-update-prompt__action {\n    text-align: center;\n  }\n}\n\n@media (prefers-reduced-motion: reduce) {\n  .ns-desktop-update-prompt__action {\n    transition: none;\n  }\n}\n";
const template_027 =
  "/**\n * @component DesktopUpdatePrompt\n * @layer 2\n * @depends theme-seed\n * @description Exhaustive update-ready UX for automatic relaunch and manual installer paths.\n */\n\nimport type { AutoUpdateReadyEvent } from '@netscript/sdk/auto-update';\nimport type { VNode } from 'preact';\n\n/** Props for the desktop update-ready prompt. */\nexport interface DesktopUpdatePromptProps {\n  /** Discriminated ready event emitted by `@netscript/sdk/auto-update`. */\n  readonly event: AutoUpdateReadyEvent;\n  /** Optional host callback for an automatic update restart action. */\n  readonly onRestart?: () => void;\n  /** Additional root class name. */\n  readonly class?: string;\n}\n\nfunction classes(...values: Array<string | undefined>): string {\n  return values.filter((value): value is string => value !== undefined && value.length > 0).join(\n    ' ',\n  );\n}\n\nfunction assertNever(value: never): never {\n  throw new TypeError(`Unsupported desktop update apply mode: ${String(value)}`);\n}\n\n/** Render the exact automatic or manual application path carried by the ready-event contract. */\nexport function DesktopUpdatePrompt({\n  event,\n  onRestart,\n  class: className,\n}: DesktopUpdatePromptProps): VNode {\n  switch (event.applyMode) {\n    case 'automatic':\n      return (\n        <aside\n          aria-live='polite'\n          class={classes('ns-desktop-update-prompt', className)}\n          data-part='update-prompt'\n          data-state='automatic'\n          role='status'\n        >\n          <div class='ns-desktop-update-prompt__copy' data-part='copy'>\n            <strong class='ns-desktop-update-prompt__title'>Update ready — restart to apply</strong>\n            <span class='ns-desktop-update-prompt__description'>\n              Version {event.version} has been verified and staged.\n            </span>\n          </div>\n          {onRestart === undefined ? null : (\n            <button\n              type='button'\n              class='ns-desktop-update-prompt__action'\n              data-part='action'\n              onClick={onRestart}\n            >\n              Restart now\n            </button>\n          )}\n        </aside>\n      );\n    case 'manual':\n      return (\n        <aside\n          aria-live='polite'\n          class={classes('ns-desktop-update-prompt', className)}\n          data-part='update-prompt'\n          data-state='manual'\n          role='status'\n        >\n          <div class='ns-desktop-update-prompt__copy' data-part='copy'>\n            <strong class='ns-desktop-update-prompt__title'>Update ready — install manually</strong>\n            <span class='ns-desktop-update-prompt__description'>\n              Version {event.version} requires the Windows installer to finish updating.\n            </span>\n          </div>\n          <a\n            class='ns-desktop-update-prompt__action'\n            data-part='action'\n            href={event.manualUpdateUrl}\n            rel='noreferrer noopener'\n            target='_blank'\n          >\n            Open installer\n          </a>\n        </aside>\n      );\n    default:\n      return assertNever(event);\n  }\n}\n";
