  '.ns-markdown {\n  color: var(--ns-fg);\n  font-family: var(--ns-font-sans);\n  font-size: var(--ns-text-sm);\n  line-height: 1.65;\n  overflow-wrap: anywhere;\n}\n\n.ns-markdown > :first-child {\n  margin-top: 0;\n}\n\n.ns-markdown > :last-child {\n  margin-bottom: 0;\n}\n\n.ns-markdown p,\n.ns-markdown ul,\n.ns-markdown ol,\n.ns-markdown blockquote,\n.ns-markdown pre,\n.ns-markdown table {\n  margin-block: var(--ns-space-3);\n}\n\n.ns-markdown h1,\n.ns-markdown h2,\n.ns-markdown h3,\n.ns-markdown h4 {\n  margin-block: var(--ns-space-4) var(--ns-space-2);\n  font-weight: 600;\n  line-height: 1.3;\n}\n\n.ns-markdown h1 {\n  font-size: var(--ns-text-lg);\n}\n\n.ns-markdown h2,\n.ns-markdown h3,\n.ns-markdown h4 {\n  font-size: var(--ns-text-sm);\n}\n\n.ns-markdown a {\n  color: var(--ns-primary);\n  text-decoration: underline;\n  text-underline-offset: 2px;\n}\n\n.ns-markdown a:hover {\n  color: color-mix(in srgb, var(--ns-primary) 80%, var(--ns-fg));\n}\n\n/* Own the list markers: host resets (Tailwind preflight, Fresh scaffolds)\n   zero out list-style, which silently drops bullets from rendered prose. */\n.ns-markdown ul,\n.ns-markdown ol {\n  list-style-position: outside;\n  padding-inline-start: var(--ns-space-5);\n}\n\n.ns-markdown ul {\n  list-style-type: disc;\n}\n\n.ns-markdown ol {\n  list-style-type: decimal;\n}\n\n.ns-markdown li::marker {\n  color: var(--ns-muted-fg);\n}\n\n.ns-markdown li {\n  margin-block: var(--ns-space-1);\n}\n\n.ns-markdown blockquote {\n  padding-inline-start: var(--ns-space-3);\n  border-inline-start: 2px solid var(--ns-primary-border);\n  color: var(--ns-muted-fg);\n}\n\n.ns-markdown code {\n  font-family: var(--ns-font-mono);\n  font-size: 0.85em;\n}\n\n.ns-markdown :not(pre) > code {\n  padding: var(--ns-space-px) var(--ns-space-1);\n  border: 1px solid var(--ns-border);\n  border-radius: var(--ns-radius-sm);\n  background: color-mix(in srgb, var(--ns-muted-fg) 12%, transparent);\n}\n\n.ns-markdown pre {\n  padding: var(--ns-space-3);\n  border: 1px solid var(--ns-border);\n  border-radius: var(--ns-radius-md);\n  background: var(--ns-surface);\n  overflow-x: auto;\n}\n\n.ns-markdown pre code {\n  padding: 0;\n  border: 0;\n  background: transparent;\n}\n\n.ns-markdown table {\n  width: 100%;\n  border-collapse: collapse;\n  font-size: var(--ns-text-xs);\n}\n\n.ns-markdown th,\n.ns-markdown td {\n  padding: var(--ns-space-2) var(--ns-space-3);\n  border: 1px solid var(--ns-border);\n  text-align: start;\n}\n\n.ns-markdown th {\n  background: color-mix(in srgb, var(--ns-muted-fg) 8%, transparent);\n  font-weight: 600;\n}\n\n.ns-markdown hr {\n  margin-block: var(--ns-space-4);\n  border: 0;\n  border-top: 1px solid var(--ns-border);\n}\n\n.ns-markdown .katex-display {\n  margin-block: var(--ns-space-3);\n  overflow-x: auto;\n  overflow-y: hidden;\n}\n\n/* Syntax highlighting palette for rehype-highlight output. Registry-owned and\n   token-driven so code colors follow the active theme — a stock highlight.js\n   stylesheet is theme-fixed and breaks contrast on the opposite theme. */\n.ns-markdown .hljs-comment,\n.ns-markdown .hljs-quote,\n.ns-markdown .hljs-meta {\n  color: var(--ns-muted-fg);\n  font-style: italic;\n}\n\n.ns-markdown .hljs-keyword,\n.ns-markdown .hljs-selector-tag,\n.ns-markdown .hljs-doctag,\n.ns-markdown .hljs-tag,\n.ns-markdown .hljs-name {\n  color: var(--ns-primary);\n}\n\n.ns-markdown .hljs-string,\n.ns-markdown .hljs-regexp,\n.ns-markdown .hljs-addition {\n  color: var(--ns-success);\n}\n\n.ns-markdown .hljs-number,\n.ns-markdown .hljs-literal,\n.ns-markdown .hljs-symbol,\n.ns-markdown .hljs-bullet,\n.ns-markdown .hljs-link {\n  color: var(--ns-warning);\n}\n\n.ns-markdown .hljs-title,\n.ns-markdown .hljs-section,\n.ns-markdown .hljs-attr,\n.ns-markdown .hljs-attribute,\n.ns-markdown .hljs-selector-id,\n.ns-markdown .hljs-selector-class,\n.ns-markdown .hljs-template-variable,\n.ns-markdown .hljs-variable {\n  color: var(--ns-secondary);\n}\n\n.ns-markdown .hljs-built_in,\n.ns-markdown .hljs-type,\n.ns-markdown .hljs-class {\n  color: color-mix(in srgb, var(--ns-secondary) 60%, var(--ns-fg));\n}\n\n.ns-markdown .hljs-deletion {\n  color: var(--ns-destructive);\n}\n\n.ns-markdown .hljs-emphasis {\n  font-style: italic;\n}\n\n.ns-markdown .hljs-strong {\n  font-weight: 600;\n}\n';
const template_052 =
  "/**\n * @component Markdown\n * @layer 3\n * @depends theme-seed, citation-chip\n * @description Sanitized GFM + math + syntax-highlighted renderer for streamed\n * assistant / chat output. Uses a unified pipeline with `remark-gfm` +\n * `remark-math` + the local `remarkCitations` transform, then `rehype-katex` +\n * `rehype-highlight`, a MANDATORY `rehype-sanitize` pass, and `rehype-react`\n * configured with the Preact JSX runtime. `stripIncompleteSyntax` guards a\n * truncated mid-stream chunk so partial syntax never renders as raw markers.\n *\n * Copy-based item — the npm dependencies (`unified`, `remark-*`, `rehype-*`,\n * `katex`, `highlight.js`) are declared on the registry item and are merged into\n * the CONSUMING app's `deno.json`, never into `@netscript/fresh-ui`.\n *\n * App wiring: the final hast tree compiles directly through `preact/jsx-runtime`;\n * no React compatibility alias is required. KaTeX styles are imported by the\n * styles aggregator this item contributes.\n */\n\nimport { Fragment, type VNode } from 'preact';\nimport { jsx, jsxs } from 'preact/jsx-runtime';\nimport rehypeReact from 'rehype-react';\nimport remarkGfm from 'remark-gfm';\nimport remarkMath from 'remark-math';\nimport remarkParse from 'remark-parse';\nimport remarkRehype from 'remark-rehype';\nimport rehypeKatex from 'rehype-katex';\nimport rehypeHighlight from 'rehype-highlight';\nimport rehypeSanitize, { defaultSchema } from 'rehype-sanitize';\nimport { unified } from 'unified';\nimport { CitationChip } from './citation-chip.tsx';\nimport {\n  extendSanitizeSchema,\n  rehypeInlineStyles,\n  remarkCitations,\n  stripIncompleteSyntax,\n} from './markdown-pipeline.ts';\n\n/** Sanitize schema is built once: citation chips + KaTeX + hljs allowed, scripts never. */\nconst SANITIZE_SCHEMA = extendSanitizeSchema(defaultSchema);\n\n/** Properties emitted by the citation mdast transform. */\ninterface CitationElementProps {\n  index?: string | number;\n  source?: string;\n}\n\n/** Per-render state captured by the citation component mapping. */\ninterface MarkdownProcessorOptions {\n  activeCite?: number;\n  onCite?: (index: number) => void;\n}\n\n/**\n * Creates the direct unified-to-Preact processor for one Markdown render.\n * Pipeline order is load-bearing: sanitize is the final content transform and\n * is never caller-configurable. `rehypeInlineStyles` only reshapes already-safe\n * style strings before the Preact compiler, preserving KaTeX layout.\n */\nfunction createMarkdownProcessor({ activeCite, onCite }: MarkdownProcessorOptions) {\n  const components = {\n    'citation-chip': (props: CitationElementProps): VNode => {\n      const index = Number(props.index);\n      return (\n        <CitationChip\n          index={index}\n          source={props.source}\n          active={activeCite === index}\n          onClick={onCite}\n        />\n      );\n    },\n  };\n\n  return unified()\n    .use(remarkParse)\n    .use(remarkGfm)\n    .use(remarkMath)\n    .use(remarkCitations)\n    .use(remarkRehype)\n    .use(rehypeKatex)\n    .use(rehypeHighlight)\n    .use(rehypeSanitize, SANITIZE_SCHEMA)\n    .use(rehypeInlineStyles)\n    .use(rehypeReact, {\n      Fragment,\n      jsx,\n      jsxs,\n      elementAttributeNameCase: 'html',\n      stylePropertyNameCase: 'dom',\n      components,\n    });\n}\n\n/** Props for the {@link Markdown} renderer. */\nexport interface MarkdownProps {\n  /** Raw model / assistant markdown source. */\n  children: string;\n  /** Pre-process a possibly-truncated mid-stream chunk before rendering. */\n  streaming?: boolean;\n  /** Invoked with the citation index when a rendered chip is activated. */\n  onCite?: (index: number) => void;\n  /** Currently active citation index (highlights its chip). */\n  activeCite?: number;\n  /** Extra class names for the wrapper. */\n  class?: string;\n}\n\n/**\n * Renders sanitized markdown from streamed assistant output.\n * @param props - {@link MarkdownProps}.\n * @returns The rendered prose surface.\n */\nexport function Markdown(\n  { children, streaming = false, onCite, activeCite, class: className }: MarkdownProps,\n): VNode {\n  const source = streaming ? stripIncompleteSyntax(children) : children;\n  const content = createMarkdownProcessor({ activeCite, onCite }).processSync(source).result;\n\n  return (\n    <div class={className ? `ns-markdown ${className}` : 'ns-markdown'}>\n      {content}\n    </div>\n  );\n}\n";
