const template_094 =
  "/**\n * @component McpUiWidget\n * @layer 3\n * @depends theme-seed\n * @description Themed, sandboxed `ui://` widget frame for MCP generative UI.\n *\n * Renders an `<iframe>` against a caller-supplied, already-resolved `ui://`\n * source — the origin owned by the `@netscript/fresh/ai` sandbox route handler\n * (FA3), never a same-origin application route. The frame is sandboxed with\n * `allow-scripts` only and **never** `allow-same-origin`, so the embedded\n * document is an opaque origin that cannot reach the host page, cookies, or\n * storage regardless of where `src` points.\n *\n * The iframe is keyed on the active `theme`. When the consumer re-renders the\n * widget with a new theme, the key change forces a full unmount + remount, so\n * the frame always loads a fresh, correctly-themed sandbox document instead of\n * reusing a stale iframe with the previous theme's tokens baked in.\n */\n\nimport { h } from 'preact';\nimport type { VNode } from 'preact';\n\n/** Props for {@link McpUiWidget}. */\nexport interface McpUiWidgetProps {\n  /**\n   * The resolved `ui://` source served by the FA3 sandbox route (an absolute\n   * URL or an app-relative path to that handler). This is the frame origin; it\n   * must never be a same-origin application route.\n   */\n  src: string;\n  /** Active theme name. The iframe is keyed on this value for remount-on-change. */\n  theme: string;\n  /** Accessible title for the frame. Defaults to `\"MCP UI widget\"`. */\n  title?: string;\n  /**\n   * Optional sandbox override. `allow-same-origin` is always stripped and\n   * `allow-scripts` is always guaranteed, so the frame stays restrictive on\n   * every render path. Defaults to {@link MCP_UI_WIDGET_DEFAULT_SANDBOX}.\n   */\n  sandbox?: string;\n}\n\n/** The only sandbox token granted by default: scripts, never same-origin. */\nexport const MCP_UI_WIDGET_DEFAULT_SANDBOX = 'allow-scripts';\n\n/** Default accessible title used when the caller does not supply one. */\nconst MCP_UI_WIDGET_DEFAULT_TITLE = 'MCP UI widget';\n\n/**\n * Normalize a sandbox token list so the frame is always restrictive:\n * `allow-same-origin` is removed (defense-in-depth against a same-origin\n * escape) and `allow-scripts` is guaranteed present. Token order is otherwise\n * preserved and duplicates are collapsed.\n *\n * @param sandbox Optional caller-supplied sandbox attribute value.\n * @returns A space-separated sandbox string that never grants same-origin access.\n */\nexport function sanitizeSandbox(sandbox?: string): string {\n  const seen = new Set<string>();\n  const tokens: string[] = [];\n\n  for (const token of (sandbox ?? MCP_UI_WIDGET_DEFAULT_SANDBOX).split(/\\s+/)) {\n    const normalized = token.trim().toLowerCase();\n    if (normalized === '' || normalized === 'allow-same-origin' || seen.has(normalized)) {\n      continue;\n    }\n    seen.add(normalized);\n    tokens.push(normalized);\n  }\n\n  if (!seen.has('allow-scripts')) {\n    tokens.unshift('allow-scripts');\n  }\n\n  return tokens.join(' ');\n}\n\n/**\n * Resolve the frame `src`, stamping the active theme as the `theme` query\n * parameter so the FA3 sandbox handler serves matching `--ns-*` tokens. Works\n * for both absolute URLs and app-relative paths; an unparseable value is\n * returned unchanged.\n *\n * @param src The caller-supplied `ui://`-resolved source.\n * @param theme The active theme name.\n * @returns The source with `?theme=` set to the active theme.\n */\nexport function resolveWidgetSrc(src: string, theme: string): string {\n  const sentinelOrigin = 'https://ns-mcp-ui.invalid';\n  let hadOrigin = true;\n  let url: URL;\n\n  try {\n    url = new URL(src);\n  } catch {\n    try {\n      hadOrigin = false;\n      url = new URL(src, sentinelOrigin);\n    } catch {\n      return src;\n    }\n  }\n\n  url.searchParams.set('theme', theme);\n  return hadOrigin ? url.toString() : `${url.pathname}${url.search}${url.hash}`;\n}\n\n/** Directly-inspectable iframe attributes derived from {@link McpUiWidgetProps}. */\nexport interface McpUiFrameAttributes {\n  /** Theme-stamped frame source. */\n  src: string;\n  /** Accessible frame title. */\n  title: string;\n  /** Restrictive sandbox string (never `allow-same-origin`). */\n  sandbox: string;\n  /** Lazy-load the frame until it scrolls into view. */\n  loading: 'lazy';\n  /** Never leak the host URL to the sandboxed origin. */\n  referrerpolicy: 'no-referrer';\n}\n\n/**\n * Compute the security-critical iframe attributes for a widget render. Kept\n * pure (and separate from the theme key) so every render path shares one\n * restrictive-sandbox seam and tests can assert it directly.\n *\n * @param props Widget props.\n * @returns The resolved iframe attributes.\n */\nexport function mcpUiFrameAttributes(props: McpUiWidgetProps): McpUiFrameAttributes {\n  return {\n    src: resolveWidgetSrc(props.src, props.theme),\n    title: props.title ?? MCP_UI_WIDGET_DEFAULT_TITLE,\n    sandbox: sanitizeSandbox(props.sandbox),\n    loading: 'lazy',\n    referrerpolicy: 'no-referrer',\n  };\n}\n\n/**\n * Renders a themed, sandboxed `ui://` widget frame.\n *\n * @param props Frame source, active theme, and optional title/sandbox overrides.\n * @returns A hydrated iframe keyed on the active theme.\n */\nexport default function McpUiWidget(props: McpUiWidgetProps): VNode {\n  const attributes = mcpUiFrameAttributes(props);\n\n  // The frame is created with `h()` instead of a JSX literal: the precompile\n  // JSX transform inlines intrinsic elements into static templates and silently\n  // drops `key`, which would defeat the theme-keyed remount contract. `h()`\n  // always yields a real keyed VNode, so a theme change unmounts and remounts\n  // the frame and the sandbox document reloads with the new theme — never a\n  // reused stale iframe document.\n  const frame = h('iframe', {\n    key: props.theme,\n    class: 'ns-mcp-ui-widget__frame',\n    src: attributes.src,\n    title: attributes.title,\n    sandbox: attributes.sandbox,\n    loading: attributes.loading,\n    referrerpolicy: attributes.referrerpolicy,\n  });\n\n  return <div class='ns-mcp-ui-widget'>{frame}</div>;\n}\n";
const template_095 =
  "import type { JSX, VNode } from 'preact';\nimport { useCallback, useEffect, useState } from 'preact/hooks';\nimport { cn } from '../lib/cn.ts';\nimport type { Renderable } from '../lib/public-types.ts';\n\n/**\n * Props for the registry sidebar toggle island.\n */\nexport interface SidebarToggleProps\n  extends Omit<JSX.HTMLAttributes<HTMLButtonElement>, 'class' | 'children'> {\n  class?: string;\n  sidebarSelector?: string;\n  backdropSelector?: string;\n  openLabel?: string;\n  closeLabel?: string;\n  openIcon?: Renderable;\n  closeIcon?: Renderable;\n}\n\n/**\n * Toggles the mobile dashboard sidebar and its backdrop state.\n * @param props Button, selector, and icon overrides for the toggle.\n * @returns A hydrated sidebar toggle button.\n */\nexport default function SidebarToggle({\n  class: className,\n  sidebarSelector = '[data-sidebar]',\n  backdropSelector = '[data-sidebar-backdrop]',\n  openLabel = 'Open sidebar',\n  closeLabel = 'Close sidebar',\n  openIcon,\n  closeIcon,\n  ...props\n}: SidebarToggleProps): VNode {\n  const [open, setOpen] = useState(false);\n  const toggle = useCallback(() => setOpen((prev) => !prev), []);\n  const close = useCallback(() => setOpen(false), []);\n\n  useEffect(() => {\n    const sidebar = document.querySelector(sidebarSelector);\n    const backdrop = document.querySelector(backdropSelector);\n    const handleEscape = (event: KeyboardEvent) => {\n      if (event.key === 'Escape') close();\n    };\n\n    sidebar?.classList.toggle('is-open', open);\n    backdrop?.classList.toggle('is-visible', open);\n\n    if (open) {\n      document.body.style.overflow = 'hidden';\n      document.addEventListener('keydown', handleEscape);\n      backdrop?.addEventListener('click', close);\n    }\n\n    return () => {\n      document.removeEventListener('keydown', handleEscape);\n      backdrop?.removeEventListener('click', close);\n      document.body.style.overflow = '';\n    };\n  }, [backdropSelector, close, open, sidebarSelector]);\n\n  useEffect(() => {\n    const handleNavigation = () => close();\n    globalThis.addEventListener('popstate', handleNavigation);\n    return () => globalThis.removeEventListener('popstate', handleNavigation);\n  }, [close]);\n\n  return (\n    <button\n      {...props}\n      type='button'\n      class={cn(\n        'ns-dashboard__mobile-trigger ns-btn ns-btn--ghost ns-btn--icon ns-btn--sm',\n        className,\n      )}\n      aria-label={open ? closeLabel : openLabel}\n      aria-expanded={open}\n      onClick={toggle}\n    >\n      <span aria-hidden='true' style={{ fontSize: '1.1rem', lineHeight: 1 }}>\n        {open ? closeIcon ?? '✕' : openIcon ?? '☰'}\n      </span>\n    </button>\n  );\n}\n";
const template_096 =
  '/* ThemeToggle island styles. */\n\n.ns-theme-toggle {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 2.25rem;\n  height: 2.25rem;\n  border: 1px solid var(--ns-border);\n  border-radius: var(--ns-radius-md);\n  background: transparent;\n  color: var(--ns-muted-fg);\n  cursor: pointer;\n  transition: color 150ms ease, background-color 150ms ease, border-color 150ms ease;\n}\n\n.ns-theme-toggle:hover {\n  border-color: var(--ns-border-hover);\n  background: var(--ns-surface-raised);\n  color: var(--ns-fg);\n}\n\n.ns-theme-toggle:focus-visible {\n  outline: 2px solid var(--ns-ring);\n  outline-offset: 2px;\n}\n';
const template_097 =
  "/**\n * @component ThemeToggle\n * @layer 2\n * @depends theme-seed\n * @description Generic Fresh island for dark/light theme switching.\n */\n\nimport { useSignal } from '@preact/signals';\nimport type { VNode } from 'preact';\nimport { useEffect } from 'preact/hooks';\n\ntype ThemeMode = 'dark' | 'light';\n\nconst STORAGE_KEY = 'ns-theme';\n\n/**\n * Resolves the initial theme without side effects. Order of authority:\n * an explicit `data-theme` already stamped by the host document, a stored\n * user preference, then the OS preference. Tokens are light-by-default,\n * so light is the fallback.\n */\nfunction getInitialTheme(): ThemeMode {\n  if (typeof document === 'undefined') {\n    return 'light';\n  }\n\n  const stamped = document.documentElement.getAttribute('data-theme');\n\n  if (stamped === 'light' || stamped === 'dark') {\n    return stamped;\n  }\n\n  const stored = localStorage.getItem(STORAGE_KEY);\n\n  if (stored === 'light' || stored === 'dark') {\n    return stored;\n  }\n\n  return globalThis.matchMedia?.('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';\n}\n\n/**\n * Switches the active document theme and persists explicit selections.\n * @returns A hydrated button that flips the `data-theme` attribute.\n */\nexport default function ThemeToggle(): VNode {\n  const theme = useSignal<ThemeMode>(getInitialTheme());\n\n  useEffect(() => {\n    // Reflect the resolved theme on the document, but never persist it:\n    // only an explicit user toggle writes to storage.\n    document.documentElement.setAttribute('data-theme', theme.value);\n  }, []);\n\n  const toggle = () => {\n    const next = theme.value === 'dark' ? 'light' : 'dark';\n    theme.value = next;\n    document.documentElement.setAttribute('data-theme', next);\n    localStorage.setItem(STORAGE_KEY, next);\n  };\n\n  return (\n    <button\n      type='button'\n      onClick={toggle}\n      class='ns-theme-toggle'\n      aria-label={`Switch to ${theme.value === 'dark' ? 'light' : 'dark'} mode`}\n      title={`Switch to ${theme.value === 'dark' ? 'light' : 'dark'} mode`}\n    >\n      {theme.value === 'dark'\n        ? (\n          <svg\n            width='16'\n            height='16'\n            viewBox='0 0 24 24'\n            fill='none'\n            stroke='currentColor'\n            strokeWidth='2'\n            strokeLinecap='round'\n            strokeLinejoin='round'\n          >\n            <circle cx='12' cy='12' r='5' />\n            <line x1='12' y1='1' x2='12' y2='3' />\n            <line x1='12' y1='21' x2='12' y2='23' />\n            <line x1='4.22' y1='4.22' x2='5.64' y2='5.64' />\n            <line x1='18.36' y1='18.36' x2='19.78' y2='19.78' />\n            <line x1='1' y1='12' x2='3' y2='12' />\n            <line x1='21' y1='12' x2='23' y2='12' />\n            <line x1='4.22' y1='19.78' x2='5.64' y2='18.36' />\n            <line x1='18.36' y1='5.64' x2='19.78' y2='4.22' />\n          </svg>\n        )\n        : (\n          <svg\n            width='16'\n            height='16'\n            viewBox='0 0 24 24'\n            fill='none'\n            stroke='currentColor'\n            strokeWidth='2'\n            strokeLinecap='round'\n            strokeLinejoin='round'\n          >\n            <path d='M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z' />\n          </svg>\n        )}\n    </button>\n  );\n}\n";
const template_098 =
  "/**\n * @component Toast\n * @layer 2\n * @depends theme-seed, toast-support\n * @description Redirect-flash notification island for Fresh applications.\n */\n\nimport { useEffect, useRef, useState } from 'preact/hooks';\nimport type { VNode } from 'preact';\nimport { type RegistryToast, type RegistryToastType, stripToastFromUrl } from '../lib/toast.ts';\n\ninterface ToastIslandProps extends Partial<RegistryToast> {\n  cleanUrl?: string;\n  duration?: number;\n}\n\nconst TOAST_SYMBOLS: Record<RegistryToastType, string> = {\n  success: '◎',\n  error: '≠',\n  warning: '⟳',\n  info: '⊕',\n};\n\nconst TOAST_LABELS: Record<RegistryToastType, string> = {\n  success: 'Success',\n  error: 'Error',\n  warning: 'Warning',\n  info: 'Notice',\n};\n\n/**\n * Renders a redirect-flash toast and cleans toast query params from the URL.\n * @param props Toast payload and timing overrides.\n * @returns A hydrated toast notification or `null` when inactive.\n */\nexport default function Toast(\n  { message, title, type = 'info', duration = 4200, cleanUrl }: ToastIslandProps,\n): VNode | null {\n  const exitTimeoutRef = useRef<ReturnType<typeof setTimeout>>();\n  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout>>();\n  const urlCleanupTimeoutRef = useRef<ReturnType<typeof setTimeout>>();\n  const countdownStartedAtRef = useRef<number>(0);\n  const remainingTimeRef = useRef<number>(duration);\n  const [visible, setVisible] = useState(Boolean(message));\n  const [exiting, setExiting] = useState(false);\n  const [instanceKey, setInstanceKey] = useState('');\n  const [paused, setPaused] = useState(false);\n\n  const cleanup = () => {\n    if (exitTimeoutRef.current) {\n      globalThis.clearTimeout(exitTimeoutRef.current);\n    }\n\n    if (hideTimeoutRef.current) {\n      globalThis.clearTimeout(hideTimeoutRef.current);\n    }\n\n    if (urlCleanupTimeoutRef.current) {\n      globalThis.clearTimeout(urlCleanupTimeoutRef.current);\n    }\n  };\n\n  const normalizeBrowserUrl = () => {\n    const targetUrl = cleanUrl ?? stripToastFromUrl(new URL(globalThis.location.href));\n    let attempts = 0;\n\n    const applyCleanUrl = () => {\n      const currentUrl =\n        `${globalThis.location.pathname}${globalThis.location.search}${globalThis.location.hash}`;\n\n      if (currentUrl !== targetUrl) {\n        globalThis.history.replaceState(globalThis.history.state, '', targetUrl);\n      }\n\n      attempts += 1;\n\n      if (attempts < 10) {\n        urlCleanupTimeoutRef.current = globalThis.setTimeout(applyCleanUrl, 50);\n      }\n    };\n\n    applyCleanUrl();\n  };\n\n  const dismiss = () => {\n    cleanup();\n    setExiting(true);\n    hideTimeoutRef.current = globalThis.setTimeout(() => setVisible(false), 220);\n  };\n\n  const scheduleDismiss = (delay: number) => {\n    if (delay <= 0) {\n      dismiss();\n      return;\n    }\n\n    countdownStartedAtRef.current = Date.now();\n    exitTimeoutRef.current = globalThis.setTimeout(() => dismiss(), delay);\n  };\n\n  const pauseDismiss = () => {\n    if (paused || exiting) {\n      return;\n    }\n\n    if (exitTimeoutRef.current) {\n      const elapsed = Date.now() - countdownStartedAtRef.current;\n      remainingTimeRef.current = Math.max(remainingTimeRef.current - elapsed, 0);\n      globalThis.clearTimeout(exitTimeoutRef.current);\n      exitTimeoutRef.current = undefined;\n    }\n\n    setPaused(true);\n  };\n\n  const resumeDismiss = () => {\n    if (!paused || exiting) {\n      return;\n    }\n\n    setPaused(false);\n    scheduleDismiss(remainingTimeRef.current);\n  };\n\n  useEffect(() => {\n    if (!message) {\n      cleanup();\n      setVisible(false);\n      return;\n    }\n\n    cleanup();\n    setVisible(true);\n    setExiting(false);\n    setPaused(false);\n    setInstanceKey(globalThis.crypto.randomUUID());\n    remainingTimeRef.current = duration;\n    normalizeBrowserUrl();\n    scheduleDismiss(duration);\n\n    return () => cleanup();\n  }, [cleanUrl, duration, message, title, type]);\n\n  if (!message || !visible) {\n    return null;\n  }\n\n  return (\n    <div\n      key={instanceKey}\n      class={`ns-toast-wrapper ${exiting ? 'ns-toast-exit' : 'ns-toast-enter'}`}\n    >\n      <div\n        class={`ns-toast ns-toast--${type}`}\n        onMouseEnter={pauseDismiss}\n        onMouseLeave={resumeDismiss}\n      >\n        <div class='ns-toast__progress-track'>\n          <div\n            class='ns-toast__progress-bar'\n            style={{\n              animation: `ns-toast-progress ${duration}ms linear forwards`,\n              animationPlayState: paused ? 'paused' : 'running',\n            }}\n          />\n        </div>\n\n        <div class='ns-toast__panel'>\n          <div class='ns-toast__header'>\n            <div class='ns-toast__title-row'>\n              <div class='ns-toast__symbol'>{TOAST_SYMBOLS[type]}</div>\n              <div class='ns-toast__title-group'>\n                <p class='ns-toast__eyebrow'>{TOAST_LABELS[type]}</p>\n                <p class='ns-toast__title'>{title ?? TOAST_LABELS[type]}</p>\n              </div>\n            </div>\n\n            <button\n              type='button'\n              aria-label='Dismiss notification'\n              class='ns-toast__dismiss'\n              onClick={dismiss}\n            >\n              ×\n            </button>\n          </div>\n\n          <p class='ns-toast__message'>{message}</p>\n        </div>\n      </div>\n    </div>\n  );\n}\n";
